+/// Convert primitive i64 to PyString
+pub fn intToString(allocator: std.mem.Allocator, value: i64) !*PyObject {
+    const str = try std.fmt.allocPrint(allocator, "{}", .{value});
+    return try PyString.create(allocator, str);
